from datetime import datetime


def parse_jobs(rows):
    jobs = []
    for row in rows:
        jobs.append({
            'id': row['id'],
            'owner': row['owner'],
            'start': row['start'],
            'duration_min': row['duration_min'],
            'priority': row.get('priority', 'normal'),
        })
    return jobs


def build_schedule(jobs):
    scheduled = []
    rejected = []
    for job in sorted(jobs, key=lambda item: item['start']):
        conflict = False
        for existing in scheduled:
            if job['start'] == existing['start']:
                conflict = True
        if conflict:
            rejected.append({'id': job['id'], 'reason': 'overlap'})
        else:
            scheduled.append(job)
    return {'scheduled': scheduled, 'rejected': rejected}


def summarize_schedule(plan):
    return {'scheduled_count': len(plan['scheduled']), 'rejected_count': len(plan['rejected'])}
